GoodsRandomPoolConfig = {}

function GoodsRandomPoolConfig:initConfig(configs)
    for _, config in pairs(configs) do
        local Range = StringUtil.split(config.NumRange, "#")
        local MinNum = 1
        local MaxNum = 1
        if #Range == 2 then
            MinNum = tonumber(Range[1])
            MaxNum = tonumber(Range[2])
        end
        if #Range == 1 then
            MinNum = tonumber(Range[1])
            MaxNum = tonumber(Range[1])
        end
        local data = {
            PoolId = tonumber(config.PoolId),
            Goods = StoreGoodsConfig:getGoodsById(tonumber(config.GoodsId)),
            Weight = tonumber(config.Weight),
            MinNum = MinNum,
            MaxNum = MaxNum,
        }
        if data.Goods ~= nil then
            GoodsPoolManager:addGoodsPoolItemToPool(data)
        end
    end
end

return GoodsRandomPoolConfig